import pymysql
from http.server import BaseHTTPRequestHandler, HTTPServer

def get_db_connection():
    return pymysql.connect(
        host='your_host',
        user='your_user',
        password='your_password',
        db='your_database'
    )

class SearchAPIHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        # Parse query parameters
        from urllib.parse import urlparse, parse_qs
        parsed_url = urlparse(self.path)
        query_params = parse_qs(parsed_url.query)

        # Construct dynamic SQL query
        sql = "SELECT * FROM your_table WHERE 1=1"
        if 'name' in query_params:
            sql += f" AND name LIKE '%{query_params['name'][0]}%'"
        if 'age' in query_params:
            sql += f" AND age = {int(query_params['age'][0])}"

        # Execute the query
        connection = get_db_connection()
        try:
            with connection.cursor() as cursor:
                cursor.execute(sql)
                results = cursor.fetchall()

            # Send response
            self.send_response(200)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            self.wfile.write(results)
        finally:
            connection.close()

def run(server_class=HTTPServer, handler_class=SearchAPIHandler, port=8080):
    server_address = ('', port)
    httpd = server_class(server_address, handler_class)
    print(f'Starting httpd server on port {port}')
    httpd.serve_forever()

if __name__ == '__main__':
    run()